import{c as e,Q as r,j as i,m as l}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"2026 Q1 AI 月報 Executive Brief","description":"","frontmatter":{"title":"2026 Q1 AI 月報 Executive Brief","source":"18 份 newsletter、155 篇文章","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-q1-brief.md","filePath":"research/ai-news/2026-q1-brief.md","lastUpdated":1779894392000}'),a={name:"research/ai-news/2026-q1-brief.md"};function d(o,t,n,s,h,u){return r(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="_2026-q1-ai-月報-executive-brief" tabindex="-1">2026 Q1 AI 月報 Executive Brief <a class="header-anchor" href="#_2026-q1-ai-月報-executive-brief" aria-label="Permalink to &quot;2026 Q1 AI 月報 Executive Brief&quot;">​</a></h1><blockquote><p>個人快速回顧｜SRE / Cloud Architect 視角｜2026-01 ~ 2026-03<br> 來源：18 份 newsletter、155 篇文章</p></blockquote><hr><h2 id="季度三大轉折" tabindex="-1">季度三大轉折 <a class="header-anchor" href="#季度三大轉折" aria-label="Permalink to &quot;季度三大轉折&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>轉折</th><th>影響</th></tr></thead><tbody><tr><td>1</td><td><strong>「選模型」→「組系統」</strong></td><td>Harness 層成為工程護城河；代理自主性是一級設計考量</td></tr><tr><td>2</td><td><strong>本地部署經濟反轉</strong></td><td>on-prem TCO 首次優於 API；企業本地部署破冰</td></tr><tr><td>3</td><td><strong>推理效率成新競爭軸</strong></td><td>速度/成本/易用/品質四維框架取代參數大小比較</td></tr></tbody></table><hr><h2 id="top-10-事件" tabindex="-1">Top 10 事件 <a class="header-anchor" href="#top-10-事件" aria-label="Permalink to &quot;Top 10 事件&quot;">​</a></h2><h3 id="🔴-立即影響" tabindex="-1">🔴 立即影響 <a class="header-anchor" href="#🔴-立即影響" aria-label="Permalink to &quot;🔴 立即影響&quot;">​</a></h3><p><strong>1. Claude Code 源碼洩露（3/18）+ OpenClaw RCE 漏洞</strong></p><ul><li>500k+ 行原始碼洩露；DMCA 移除；三層記憶架構曝光</li><li>OpenClaw：10,000+ 實例暴露（BitStrike）；100,000+ 存在 RCE（BitDefender）</li><li><em>SRE 行動</em>：自托管代理框架必須納入 0-trust 審查；deny-list 是底線</li></ul><p><strong>2. Axios npm 汙染 + Mercor breach（3/31）</strong></p><ul><li>Axios：100M 週安裝量受威脅；代理工具鏈串聯風險</li><li>Mercor：AI 承包商資料批量外洩</li><li><em>SRE 行動</em>：pin 所有 npm 依賴版本；啟用 SBOM 掃描；LiteLLM 版本審查</li></ul><p><strong>3. Anthropic 被 Pentagon 移除（3/16，150 秒內）</strong></p><ul><li>供應鏈風險標記導致存取撤銷；Anthropic 起訴 Trump 政府</li><li><em>SRE 關注</em>：雲端 AI API 的主權/合規風險已從理論變實務；多供應商備援規劃</li></ul><p><strong>4. Opus 4.7 「變笨」事件（Wisely Chen 揭露）</strong></p><ul><li>Anthropic 承認 3 個 Harness Bug；context window 壓縮事件（15% ↓）</li><li><em>SRE 關注</em>：<strong>訂閱 SLA ≠ 能力穩定</strong>；關鍵工作流要建立模型品質監控</li></ul><hr><h3 id="🟠-策略影響-1-3-個月" tabindex="-1">🟠 策略影響（1-3 個月） <a class="header-anchor" href="#🟠-策略影響-1-3-個月" aria-label="Permalink to &quot;🟠 策略影響（1-3 個月）&quot;">​</a></h3><p><strong>5. 本地部署 TCO 反轉（Wisely Chen 精算）</strong></p><ul><li>Qwen 3.6-27B on-prem 3 年 TCO：$4.7k vs API 方案 $22.5k（DGX Spark）</li><li><em>行動</em>：開始為企業 AI Coding 工作流評估本地/混合部署；計算完整 TCO</li></ul><p><strong>6. GPT-5.4 定價與 Claude Opus 4.6 競爭格局</strong></p><ul><li>GPT-5.4：$2.50/$15 per 1M；GPT-5.4 Pro 輸出 $180/1M</li><li>Claude Opus 4.6 快速版：$150/1M 輸出；1M context GA</li><li><em>行動</em>：重新評估 API 預算；快速版 vs 標準版成本差 6×</li></ul><p><strong>7. OpenAI Codex vs Claude Code 市場份額</strong></p><ul><li>Claude Code VS Code 安裝：520 萬 vs Codex 490 萬</li><li>Codex 週活 220 萬；日均 5T token；年化 $1B run-rate</li><li><em>關注</em>：代理編碼工具已是主流基礎設施，採用時機影響競爭力</li></ul><p><strong>8. Harness Engineering 正式成工程學科（Q1 定義，Q2 爆發）</strong></p><ul><li>One Useful Thing「Model/App/Harness」三層架構：控制力集中於 Harness 層</li><li><em>行動</em>：評估團隊 Harness 能力缺口；投資 inference framework、路由、量化</li></ul><hr><h3 id="🟡-觀望追蹤-3-6-個月" tabindex="-1">🟡 觀望追蹤（3-6 個月） <a class="header-anchor" href="#🟡-觀望追蹤-3-6-個月" aria-label="Permalink to &quot;🟡 觀望追蹤（3-6 個月）&quot;">​</a></h3><p><strong>9. 物理 AI 大額融資（但商業化仍遠）</strong></p><ul><li>AMI Labs（LeCun）$1.03B @ $3.5B；World Labs（Fei-Fei Li）$1B</li><li>OpenAI Sora 關閉（$1M/天燒費）→ 體現 AI 商業難度確認</li><li><em>關注</em>：NVIDIA NemoClaw / JEPA 開源突破作長期監控信號</li></ul><p><strong>10. 開源模型三層分化</strong></p><ul><li>邊緣層（7B）：Nemotron Nano、Kimi Linear → 本地推理</li><li>中層（70B+）：Qwen 3.5-122B、Mistral Small 4 → 追平專有模型特定任務</li><li><em>行動</em>：按場景分層選模型；停止一刀切使用雲端 API</li></ul><hr><h2 id="本季定價參考" tabindex="-1">本季定價參考 <a class="header-anchor" href="#本季定價參考" aria-label="Permalink to &quot;本季定價參考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>輸入 / 輸出（per 1M token）</th><th>備註</th></tr></thead><tbody><tr><td>GPT-5.4</td><td>$2.50 / $15</td><td>—</td></tr><tr><td>GPT-5.4 Pro</td><td>— / $180（輸出）</td><td>極端推理模式</td></tr><tr><td>Claude Opus 4.6</td><td>$25 / $25</td><td>標準</td></tr><tr><td>Claude Opus 4.6 快速</td><td>— / $150</td><td>快速版</td></tr><tr><td>Claude Code Max</td><td>$100/月</td><td>—</td></tr><tr><td>Codex 入門</td><td>$200</td><td>OpenAI pricing</td></tr><tr><td>StrongDM AI token 支出</td><td>$1,000/天/工程師</td><td>企業參考案例</td></tr></tbody></table><hr><h2 id="本季安全行動清單" tabindex="-1">本季安全行動清單 <a class="header-anchor" href="#本季安全行動清單" aria-label="Permalink to &quot;本季安全行動清單&quot;">​</a></h2><ul><li>[ ] 審查 OpenClaw / Claude Code 代理的 deny-list 與沙箱設定</li><li>[ ] Axios 及 AI 相關 npm 套件：pin 版本 + 啟用 SBOM 掃描</li><li>[ ] 建立模型品質監控（Opus 4.7 事件教訓：能力退化需可偵測）</li><li>[ ] 雲端 AI API 多供應商備援規劃（Pentagon 事件：主權/合規風險實務化）</li><li>[ ] 自托管代理框架 0-trust 審查（OpenClaw RCE 10 萬實例）</li></ul><hr><p><em>詳細版：<code>research/ai-news/2026-q1-digest.md</code>（完整 7 大主題 + 時間線 + 各來源視角）</em></p>',40)])])}const m=e(a,[["render",d]]);export{c as __pageData,m as default};
